1484:
SELECT (SUM(CASE WHEN Country = 'CZE' AND Segment = 'Discount' THEN 1 ELSE 0 END) -
        SUM(CASE WHEN Country = 'SVK' AND Segment = 'Discount' THEN 1 ELSE 0 END)) AS Difference
FROM gasstations;

1498:
SELECT MAX(Consumption) AS HighestMonthlyConsumption
FROM yearmonth
WHERE SUBSTR(Date, 1, 4) = '2012';

801:
SELECT CAST(SUM(CASE WHEN T2.gender = 'Male' THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN T2.gender = 'Female' THEN 1 ELSE 0 END) AS ratio
FROM superhero AS T1
JOIN gender AS T2 ON T1.gender_id = T2.id;

