SELECT CAST(SUM(CASE WHEN cardKingdomFoilId IS NOT NULL OR cardKingdomId IS NOT NULL THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) AS percentage_incredibly_powerful_cards
FROM cards
WHERE setCode = 'Coldsnap';
